8833 /// of a cast instruction. The function checks if it is legal to move the cast
8834 /// operation after "select". If yes, it returns the new second value of
8835 /// "select" (with the assumption that cast is moved):
8836 /// 1. As operand of cast instruction when both values of "select" are same cast
8837 /// instructions.
8838 /// 2. As restored constant (by applying reverse cast operation) when the first
8839 /// value of the "select" is a cast operation and the second value is a
8840 /// constant. It is implemented in lookThroughCastConst().
8841 /// 3. As one operand is cast instruction and the other is not. The operands in
8842 /// sel(cmp) are in different type integer.
8843 /// NOTE: We return only the new second value because the first value could be
8844 /// accessed as operand of cast instruction.
8845 static Value *lookThroughCast(CmpInst *CmpI, Value *V1, Value *V2,
8846                               Instruction::CastOps *CastOp) {
8847   auto *Cast1 = dyn_cast<CastInst>(V1);
8848   if (!Cast1)
8849     return nullptr;
8850 
8851   *CastOp = Cast1->getOpcode();
8852   Type *SrcTy = Cast1->getSrcTy();
8853   if (auto *Cast2 = dyn_cast<CastInst>(V2)) {
8854     // If V1 and V2 are both the same cast from the same type, look through V1.
8855     if (*CastOp == Cast2->getOpcode() && SrcTy == Cast2->getSrcTy())
8856       return Cast2->getOperand(0);
8857     return nullptr;
8858   }
8859 
8860   auto *C = dyn_cast<Constant>(V2);
8861   if (C)
8862     return lookThroughCastConst(CmpI, SrcTy, C, CastOp);
8863 
8864   Value *CastedTo = nullptr;
8865   if (*CastOp == Instruction::Trunc) {
8866     if (match(CmpI->getOperand(1), m_ZExtOrSExt(m_Specific(V2)))) {
8867       // Here we have the following case:
8868       //   %y_ext = sext iK %y to iN
8869       //   %cond = cmp iN %x, %y_ext
8870       //   %tr = trunc iN %x to iK
8871       //   %narrowsel = select i1 %cond, iK %tr, iK %y
8872       //
8873       // We can always move trunc after select operation:
8874       //   %y_ext = sext iK %y to iN
8875       //   %cond = cmp iN %x, %y_ext
8876       //   %widesel = select i1 %cond, iN %x, iN %y_ext
8877       //   %tr = trunc iN %widesel to iK
8878       assert(V2->getType() == Cast1->getType() &&
8879              "V2 and Cast1 should be the same type.");
8880       CastedTo = CmpI->getOperand(1);
8881     }
8882   }
8883 
8884   return CastedTo;
8885 }
