9115 /// Return true if "icmp Pred LHS RHS" is always true.
9116 static bool isTruePredicate(CmpInst::Predicate Pred, const Value *LHS,
9117                             const Value *RHS) {
9118   if (ICmpInst::isTrueWhenEqual(Pred) && LHS == RHS)
9119     return true;
9120 
9121   switch (Pred) {
9122   default:
9123     return false;
9124 
9125   case CmpInst::ICMP_SLE: {
9126     const APInt *C;
9127 
9128     // LHS s<= LHS +_{nsw} C   if C >= 0
9129     // LHS s<= LHS | C         if C >= 0
9130     if (match(RHS, m_NSWAdd(m_Specific(LHS), m_APInt(C))) ||
9131         match(RHS, m_Or(m_Specific(LHS), m_APInt(C))))
9132       return !C->isNegative();
9133 
9134     // LHS s<= smax(LHS, V) for any V
9135     if (match(RHS, m_c_SMax(m_Specific(LHS), m_Value())))
9136       return true;
9137 
9138     // smin(RHS, V) s<= RHS for any V
9139     if (match(LHS, m_c_SMin(m_Specific(RHS), m_Value())))
9140       return true;
9141 
9142     // Match A to (X +_{nsw} CA) and B to (X +_{nsw} CB)
9143     const Value *X;
9144     const APInt *CLHS, *CRHS;
9145     if (match(LHS, m_NSWAddLike(m_Value(X), m_APInt(CLHS))) &&
9146         match(RHS, m_NSWAddLike(m_Specific(X), m_APInt(CRHS))))
9147       return CLHS->sle(*CRHS);
9148 
9149     return false;
